// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentActivityInstance) predicate.AgentActivityInstance {
	return predicate.AgentActivityInstance(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentActivityInstance) predicate.AgentActivityInstance {
	return predicate.AgentActivityInstance(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentActivityInstance) predicate.AgentActivityInstance {
	return predicate.AgentActivityInstance(sql.NotPredicates(p))
}
